// Normalises lead data from Fluent Forms, CallRail, or any generic form POST.
// Sets is_valid_lead = true when the submission has recognisable contact information
// and is not a developer test submission (both name AND email contain 'test').

const item = $input.first().json;
const raw  = item.body || item;

const CALLRAIL_SIGNALS = ['caller_number', 'caller_name', 'tracking_number', 'business_phone_number'];
const isCallRail       = CALLRAIL_SIGNALS.some(f => raw[f] !== undefined);

let lead;

if (isCallRail) {
  const phone = (raw.caller_number || raw.caller_phone_number || '').trim();
  lead = {
    lead_name:    (raw.caller_name || raw.customer_name || 'Unknown Caller').trim(),
    lead_email:   (raw.email || '').trim(),
    lead_phone:   phone,
    matter_type:  (raw.campaign_name || '').trim(),
    message:      '',
    raw_source:   (raw.source || raw.utm_source || 'call').trim(),
    source_detail:(raw.keyword || raw.landing_page_url || 'CallRail').trim(),
    form_source:  'callrail',
    referrer:     (raw.landing_page_url || '').trim(),
    utm_source:   (raw.utm_source || '').trim(),
    utm_medium:   (raw.utm_medium || '').trim(),
    utm_campaign: (raw.utm_campaign || '').trim(),
    gclid:        (raw.gclid || '').trim(),
  };
} else {
  // Fluent Forms or generic JSON form POST.
  // Fluent Forms sometimes nests first/last name under a 'names' object.
  let firstName = '';
  let lastName  = '';
  if (raw.names && typeof raw.names === 'object') {
    firstName = (raw.names.first_name || raw.names.firstName || '').trim();
    lastName  = (raw.names.last_name  || raw.names.lastName  || '').trim();
  } else {
    firstName = (raw.first_name || raw.names_first_name || raw['first-name'] || '').trim();
    lastName  = (raw.last_name  || raw.names_last_name  || raw['last-name']  || '').trim();
  }
  const fullName = (raw.full_name || raw.name || `${firstName} ${lastName}`).trim();
  lead = {
    lead_name:    fullName || 'Unknown',
    lead_email:   (raw.email || raw.email_address || '').trim(),
    lead_phone:   (raw.phone || raw.phone_number  || raw.mobile || '').trim(),
    matter_type:  (raw.matter_type || raw.legal_issue || raw.practice_area || raw.case_type || '').trim(),
    message:      (raw.message || raw.comments || raw.how_can_we_help || '').trim(),
    raw_source:   (raw.utm_source || raw.source || raw.how_did_you_hear || raw.referral_source || '').trim(),
    source_detail:(raw.utm_campaign || raw.utm_content || raw.referrer || '').trim(),
    form_source:  'form',
    referrer:     (raw.referrer || raw._wp_http_referer || '').trim(),
    utm_source:   (raw.utm_source || '').trim(),
    utm_medium:   (raw.utm_medium || '').trim(),
    utm_campaign: (raw.utm_campaign || '').trim(),
    gclid:        (raw.gclid || '').trim(),
  };
}

// Require BOTH name and email to contain 'test' to suppress — avoids dropping
// real leads with names like 'Testani' when using a real email.
const isTest     = /test/i.test(lead.lead_name) && /test/i.test(lead.lead_email);
const hasContact = lead.lead_phone !== '' || lead.lead_email !== '' || (lead.lead_name !== '' && lead.lead_name !== 'Unknown');

return [{ json: {
  ...lead,
  received_at:   new Date().toISOString(),
  is_valid_lead: hasContact && !isTest,
} }];

// Maps the raw source signals to a canonical channel name for the dashboard.
// Channel is the grouping label (e.g. 'google-ads'); source_detail is the granular label.

const FIRM_NAME   = $vars.FIRM_NAME   || 'Your Firm';
const FIRM_EMAIL  = $vars.FIRM_EMAIL;
const BOOKING_URL = $vars.FIRM_BOOKING_URL || '';
const SHEET_ID    = $vars.ROI_SHEET_ID;

if (!SHEET_ID) {
  throw new Error('ROI_SHEET_ID n8n Variable is not set. Go to project → Variables tab and add it.');
}
if (!FIRM_EMAIL) {
  throw new Error('FIRM_EMAIL n8n Variable is not set. Go to project → Variables tab and add it.');
}

const item = $input.first().json;

// Combine all available source signals into one searchable string
const signals = [
  item.raw_source,
  item.utm_source,
  item.utm_medium,
  item.referrer,
].map(s => (s || '').toLowerCase()).join(' ');

const hasGclid = Boolean(item.gclid);

let channel;
if (hasGclid || /google.?ads?|google paid|cpc|ppc/i.test(signals)) {
  channel = 'google-ads';
} else if (/facebook|instagram|fb|meta|social/i.test(signals)) {
  channel = 'social-media';
} else if (/referral|referred|attorney|colleague|word.?of.?mouth|friend|family/i.test(signals)) {
  channel = 'referral';
} else if (/avvo|justia|findlaw|martindale|lawyers\.com|nolo|directory/i.test(signals)) {
  channel = 'legal-directory';
} else if (/yelp/i.test(signals)) {
  channel = 'yelp';
} else if (/email|newsletter|campaign|drip/i.test(signals)) {
  channel = 'email-campaign';
} else if (/callrail|call/i.test(item.form_source || '')) {
  channel = 'inbound-call';
} else if (/organic|seo|blog|search/i.test(signals) || item.referrer !== '') {
  channel = 'website-organic';
} else {
  channel = 'unknown';
}

const source_detail = [
  item.utm_campaign,
  item.utm_content,
  item.source_detail,
  item.raw_source,
].filter(Boolean).join(' / ') || channel;

const firstName = (item.lead_name || '').split(' ')[0] || 'there';
const ack_message = `Hi ${firstName}, thank you for reaching out to ${FIRM_NAME}. We received your inquiry and will be in touch within one business day. To schedule a consultation sooner: ${BOOKING_URL}`;

return [{ json: {
  ...item,
  channel,
  source_detail,
  firm_name:   FIRM_NAME,
  firm_email:  FIRM_EMAIL,
  booking_url: BOOKING_URL,
  sheet_id:    SHEET_ID,
  ack_message,
} }];

