// Extracts the Salesmate contact ID from the API response and merges it with the lead data.
// If the Salesmate call failed (neverError: true), the response won't have an ID — the dashboard log still proceeds.
const sm   = $input.first().json;
const lead = $('Tag Lead Source').first().json;

const salesmate_contact_id = (
  sm?.Data?.id ||
  sm?.data?.id ||
  sm?.id ||
  ''
).toString();

return [{ json: {
  ...lead,
  salesmate_contact_id,
} }];

// Builds the firm alert email content using data from earlier stable nodes.
// Runs from three paths: ack sent, ack suppressed (opted out), or no email provided.
// $json.approved is only present when the compliance check ran.
const lead    = $('Tag Lead Source').first().json;
const sm      = $('Read Salesmate Response').first().json;
const current = $input.first().json;

let ack_status;
if (current.approved === true) {
  ack_status = 'Sent ✓';
} else if (current.approved === false) {
  ack_status = 'Not sent (contact opted out)';
} else {
  // No email path: approved is undefined
  ack_status = 'Not sent (no email address provided)';
}

return [{ json: {
  lead_name:            lead.lead_name,
  lead_email:           lead.lead_email,
  lead_phone:           lead.lead_phone,
  matter_type:          lead.matter_type,
  message:              lead.message,
  channel:              lead.channel,
  source_detail:        lead.source_detail,
  received_at:          lead.received_at,
  salesmate_contact_id: sm.salesmate_contact_id || '(not created — check Salesmate credentials)',
  firm_name:            lead.firm_name,
  firm_email:           lead.firm_email,
  booking_url:          lead.booking_url,
  salesmate_base_url:   ($vars.SALESMATE_BASE_URL || '').replace(/\/$/, ''),
  ack_status,
} }];

